import { createRequire } from 'node:module';
import { Module } from '@nestjs/common';
import { WorkflowModule } from 'workflow/nest';
import { AppController } from './app.controller.js';

// Force-enable manifest serving on Vercel
if (process.env.VERCEL) {
  process.env.WORKFLOW_PUBLIC_MANIFEST = '1';
}

// Load the manifest generated by workflow-nest build.
// The NestJS CLI assets config copies it to dist/workflow/ during compilation.
// createRequire resolves relative to THIS file (dist/app.module.js).
let manifestJson: string | undefined;
const _require = createRequire(import.meta.url);
try {
  const _manifestObj = _require('./workflow/manifest.json');
  manifestJson = JSON.stringify(_manifestObj);
} catch {
  // File doesn't exist during dev (built at runtime by WorkflowModule)
}

@Module({
  imports: [
    WorkflowModule.forRoot({
      skipBuild: !!process.env.VERCEL,
      // Pass the pre-loaded manifest so the controller doesn't need readFileSync
      ...(manifestJson ? { manifestJson } : {}),
    }),
  ],
  controllers: [AppController],
})
export class AppModule {}
